#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=emulator-5554;expected=x86_64-pc-linux-gnu;reject=false;reset=false;skip=false;timeout=240;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--expected-architecture)expected="${2:?}";shift 2;;--expect-page-size-rejection)reject=true;shift;;--reset-app-data)reset=true;shift;;--skip-install)skip=true;shift;;--install-timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";terminal=org.archpheneos.terminal;[[ "$reset" == false ]] || archphene_adb_run shell pm clear "$terminal" >/dev/null;if [[ "$skip" == false ]];then for apk in "$ARCHPHENE_ROOT/prototypes/linux-app-manager-stub/out-linux/archphene.apk" "$ARCHPHENE_ROOT/prototypes/archphene-terminal-app/out-linux/archphene-terminal.apk";do archphene_require_file "$apk";archphene_adb_run install -r "$apk" >/dev/null;done;fi;abi="$(archphene_adb_run shell getprop ro.product.cpu.abi|tr -d '\r')";page="$(archphene_adb_run shell getconf PAGESIZE|tr -d '\r')";command='echo ARCHPHENE_MANAGED_SHELL_OK; uname -m';encoded="$(printf %s "$command"|base64 -w0)";archphene_adb_run logcat -c;archphene_adb_run shell am start -n "$terminal/.TerminalActivity" --es archphene_test_terminal_command_base64 "$encoded" --ei archphene_test_terminal_capture_delay_ms 5000 >/dev/null;if [[ "$reject" == true ]];then archphene_wait_log 'page size|incompatible' 45 'ArchpheneTerminal:I *:S' >/dev/null;archphene_note "Managed-shell rejection passed on $serial ($abi, $page-byte pages).";else log="$(archphene_wait_log ARCHPHENE_MANAGED_SHELL_OK "$timeout" 'ArchpheneTerminal:I ArchphenePackages:I AndroidRuntime:E *:S')";[[ "$log" == *ARCHPHENE_MANAGED_SHELL_OK* ]] || archphene_die 'managed shell command failed';archphene_note "Managed Arch Bash passed on $serial ($abi, $page-byte pages, $expected).";fi
